## 2. Implement Efficient Drawing

Minimize object allocations in the draw loop:

```csharp
public class SkiaCustomGauge : SkiaView
{
    // ❌ BAD: Allocates new objects every frame
    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        var paint = new SKPaint { Color = SKColors.Blue }; // Allocation!
        var path = new SKPath(); // Allocation!
        path.AddArc(_bounds, 0, 90);
        canvas.DrawPath(path, paint);
    }

    // ✅ GOOD: Reuse objects
    private readonly SKPaint _gaugePaint = new() { IsAntialias = true };
    private readonly SKPath _gaugePath = new();

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        _gaugePaint.Color = GaugeColor;

        _gaugePath.Reset();
        _gaugePath.AddArc(_bounds, 0, 90);

        canvas.DrawPath(_gaugePath, _gaugePaint);
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            _gaugePaint?.Dispose();
            _gaugePath?.Dispose();
        }
        base.Dispose(disposing);
    }
}
```

## 3. Use Bindable Properties Correctly

Follow MAUI's bindable property pattern:

```csharp
public class SkiaRatingControl : SkiaView
{
    public static readonly BindableProperty RatingProperty =
        BindableProperty.Create(
            nameof(Rating),
            typeof(double),
            typeof(SkiaRatingControl),
            0.0,
            propertyChanged: OnRatingChanged);

    public double Rating
    {
        get => (double)GetValue(RatingProperty);
        set => SetValue(RatingProperty, value);
    }

    private static void OnRatingChanged(BindableObject bindable, object oldValue, object newValue)
    {
        if (bindable is SkiaRatingControl control)
        {
            control.Invalidate(); // Trigger repaint
        }
    }
}
```

## 4. Implement Smart Invalidation

Differentiate between layout and paint changes:

```csharp
public class SkiaCustomPanel : SkiaLayoutView
{
    public Color BorderColor
    {
        get => _borderColor;
        set
        {
            if (_borderColor != value)
            {
                _borderColor = value;
                Invalidate(); // Paint-only change
            }
        }
    }

    public Thickness Padding
    {
        get => _padding;
        set
        {
            if (_padding != value)
            {
                _padding = value;
                InvalidateLayout(); // Affects child positioning
            }
        }
    }
}
```

## 5. Handle Gestures Properly

Implement gesture recognition with proper event propagation:

```csharp
public class SkiaInteractiveCard : SkiaView
{
    public event EventHandler<TappedEventArgs>? Tapped;
    public ICommand? TapCommand { get; set; }

    public override bool OnTouchEvent(MotionEvent motionEvent)
    {
        switch (motionEvent.Action)
        {
            case MotionEventActions.Down:
                _isPressed = true;
                Invalidate(); // Update visual state
                return true; // Consume event

            case MotionEventActions.Up:
                if (_isPressed && _bounds.Contains(motionEvent.X, motionEvent.Y))
                {
                    // Fire events
                    Tapped?.Invoke(this, new TappedEventArgs());
                    TapCommand?.Execute(null);
                }
                _isPressed = false;
                Invalidate();
                return true;

            case MotionEventActions.Cancel:
                _isPressed = false;
                Invalidate();
                return true;
        }

        return base.OnTouchEvent(motionEvent);
    }
}
```

## 6. Support Visual States

Implement visual state management for interactive controls:

```csharp
public class SkiaCustomButton : SkiaView
{
    private VisualState _currentState = VisualState.Normal;

    public enum VisualState
    {
        Normal,
        Hovered,
        Pressed,
        Disabled
    }

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        var backgroundColor = _currentState switch
        {
            VisualState.Normal => NormalColor,
            VisualState.Hovered => HoverColor,
            VisualState.Pressed => PressedColor,
            VisualState.Disabled => DisabledColor,
            _ => NormalColor
        };

        using var paint = new SKPaint
        {
            Color = backgroundColor,
            Style = SKPaintStyle.Fill
        };

        canvas.DrawRoundRect(_bounds, CornerRadius, CornerRadius, paint);
    }

    public bool IsEnabled
    {
        get => _isEnabled;
        set
        {
            _isEnabled = value;
            _currentState = value ? VisualState.Normal : VisualState.Disabled;
            Invalidate();
        }
    }
}
```

## 7. Implement Accessibility

Make controls accessible to screen readers:

