## 8. Optimize for HiDPI Displays

Handle scaling properly:

```csharp
public class SkiaScalableControl : SkiaView
{
    private float _displayScale = 1.0f;

    protected override void OnParentSet()
    {
        base.OnParentSet();
        _displayScale = GetDisplayScale();
    }

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        // Scale-aware stroke width
        var strokeWidth = 1.0f * _displayScale;

        using var paint = new SKPaint
        {
            StrokeWidth = strokeWidth,
            IsAntialias = true
        };

        canvas.DrawLine(_bounds.Left, _bounds.Top, _bounds.Right, _bounds.Bottom, paint);
    }
}
```

## 9. Use Render Caching Strategically

Enable caching for static or rarely changing content:

```csharp
public class SkiaComplexChart : SkiaView
{
    private SKPicture? _gridCache;
    private bool _gridDirty = true;

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        // Cache the static grid
        if (_gridDirty || _gridCache == null)
        {
            using var recorder = new SKPictureRecorder();
            var recordingCanvas = recorder.BeginRecording(_bounds);
            DrawGrid(recordingCanvas);
            _gridCache = recorder.EndRecording();
            _gridDirty = false;
        }

        canvas.DrawPicture(_gridCache);

        // Draw dynamic data without caching
        DrawDataPoints(canvas);
    }

    public void UpdateData(double[] newData)
    {
        _data = newData;
        Invalidate(); // Grid cache remains valid
    }
}
```

