Rendering complex UI elements every frame is expensive. OpenMaui employs sophisticated **caching strategies** to minimize redundant drawing operations, dramatically improving performance for static or infrequently changing content.

## SKPicture-Based Caching

Skia's `SKPicture` provides a recording mechanism for draw commands:

```csharp
public abstract class SkiaView
{
    private SKPicture? _cachedPicture;
    private bool _cacheDirty = true;

    public bool EnableRenderCaching { get; set; } = false;

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        if (EnableRenderCaching)
        {
            if (_cacheDirty || _cachedPicture == null)
            {
                // Record drawing commands
                using var recorder = new SKPictureRecorder();
                var recordingCanvas = recorder.BeginRecording(_bounds);

                DrawContent(recordingCanvas, dirtyRect);

                _cachedPicture?.Dispose();
                _cachedPicture = recorder.EndRecording();
                _cacheDirty = false;
            }

            // Replay cached commands
            canvas.DrawPicture(_cachedPicture);
        }
        else
        {
            // Direct rendering
            DrawContent(canvas, dirtyRect);
        }
    }

    protected abstract void DrawContent(SKCanvas canvas, SKRect dirtyRect);

    public override void Invalidate()
    {
        _cacheDirty = true;
        base.Invalidate();
    }
}
```

## Image Caching System

The `SkiaImage` control implements multi-level caching:

```csharp
public class SkiaImage : SkiaView
{
    private static readonly Dictionary<string, SKBitmap> _imageCache = new();
    private static readonly object _cacheLock = new();

    private SKBitmap? _bitmap;
    private string? _source;

    public ImageSource Source
    {
        get => _source;
        set
        {
            if (_source != value)
            {
                _source = value;
                LoadImageAsync(value);
            }
        }
    }

    private async Task LoadImageAsync(ImageSource source)
    {
        if (source is FileImageSource fileSource)
        {
            var path = fileSource.File;

            // Check memory cache first
            lock (_cacheLock)
            {
                if (_imageCache.TryGetValue(path, out var cached))
                {
                    _bitmap = cached;
                    Invalidate();
                    return;
                }
            }

            // Load from disk
            _bitmap = await Task.Run(() => SKBitmap.Decode(path));

            // Cache for future use
            lock (_cacheLock)
            {
                _imageCache[path] = _bitmap;
            }

            Invalidate();
        }
        else if (source is StreamImageSource streamSource)
        {
            var stream = await streamSource.Stream(CancellationToken.None);
            _bitmap = SKBitmap.Decode(stream);
            Invalidate();
        }
    }

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        if (_bitmap != null)
        {
            canvas.DrawBitmap(_bitmap, _bounds);
        }
    }
}
```

## SVG Caching with Svg.Skia

SVG rendering is expensive, so OpenMaui caches rasterized versions:

```csharp
public class SkiaSvgImage : SkiaImage
{
    private SKPicture? _svgPicture;
    private SKBitmap? _rasterizedCache;
    private Size _lastRenderSize;

    private void LoadSvg(string path)
    {
        var svg = new SKSvg();
        _svgPicture = svg.Load(path);
    }

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        if (_svgPicture == null)
            return;

        var currentSize = new Size(_bounds.Width, _bounds.Height);

        // Re-rasterize if size changed
        if (_rasterizedCache == null || _lastRenderSize != currentSize)
        {
            _rasterizedCache?.Dispose();

            var info = new SKImageInfo(
                (int)_bounds.Width,
                (int)_bounds.Height,
                SKColorType.Rgba8888,
                SKAlphaType.Premul
            );

            _rasterizedCache = new SKBitmap(info);

            using var cacheCanvas = new SKCanvas(_rasterizedCache);
            cacheCanvas.Clear(SKColors.Transparent);
            cacheCanvas.DrawPicture(_svgPicture);

            _lastRenderSize = currentSize;
        }

        canvas.DrawBitmap(_rasterizedCache, _bounds);
    }
}
```

