## Collection View Virtualization

The `SkiaCollectionView` implements virtualization to cache only visible items:

```csharp
public class SkiaCollectionView : SkiaView
{
    private readonly Dictionary<int, SkiaView> _visibleItemCache = new();
    private readonly HashSet<int> _currentlyVisible = new();

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        var visibleRange = CalculateVisibleRange(_scrollOffset, _bounds.Height);
        _currentlyVisible.Clear();

        for (int i = visibleRange.Start; i < visibleRange.End; i++)
        {
            _currentlyVisible.Add(i);

            if (!_visibleItemCache.TryGetValue(i, out var itemView))
            {
                // Create and cache new item view
                itemView = CreateItemView(i);
                _visibleItemCache[i] = itemView;
            }

            var itemBounds = CalculateItemBounds(i);
            itemView.Arrange(itemBounds);
            itemView.Draw(canvas, dirtyRect);
        }

        // Cleanup items that scrolled out of view
        var itemsToRemove = _visibleItemCache.Keys
            .Where(k => !_currentlyVisible.Contains(k))
            .ToList();

        foreach (var key in itemsToRemove)
        {
            _visibleItemCache[key].Dispose();
            _visibleItemCache.Remove(key);
        }
    }
}
```

## Cache Invalidation Strategy

Proper cache invalidation is critical:

```csharp
public abstract class SkiaView
{
    protected void InvalidateCache(CacheLevel level)
    {
        switch (level)
        {
            case CacheLevel.Paint:
                // Only visual properties changed
                _cacheDirty = true;
                Invalidate();
                break;

            case CacheLevel.Layout:
                // Size/position changed, invalidate layout cache
                _layoutCache = null;
                _cacheDirty = true;
                InvalidateLayout();
                break;

            case CacheLevel.Deep:
                // Structure changed, invalidate entire subtree
                InvalidateDescendants();
                _cacheDirty = true;
                InvalidateLayout();
                break;
        }
    }
}

public enum CacheLevel
{
    Paint,    // Color, stroke, etc.
    Layout,   // Size, position
    Deep      // Children added/removed
}
```

