```csharp
public class ImageCacheManager
{
    private const long MaxCacheSizeBytes = 100 * 1024 * 1024; // 100 MB
    private long _currentCacheSize = 0;

    public void AddToCache(string key, SKBitmap bitmap)
    {
        var bitmapSize = bitmap.ByteCount;

        // Evict old items if necessary
        while (_currentCacheSize + bitmapSize > MaxCacheSizeBytes)
        {
            EvictLeastRecentlyUsed();
        }

        _imageCache[key] = bitmap;
        _currentCacheSize += bitmapSize;
    }

    private void EvictLeastRecentlyUsed()
    {
        // LRU eviction logic
    }
}
