## Complete Example: Custom Progress Ring

Putting it all together:

```csharp
public class SkiaProgressRing : SkiaView
{
    private readonly SKPaint _trackPaint = new()
    {
        Style = SKPaintStyle.Stroke,
        StrokeWidth = 8,
        IsAntialias = true
    };

    private readonly SKPaint _progressPaint = new()
    {
        Style = SKPaintStyle.Stroke,
        StrokeWidth = 8,
        IsAntialias = true,
        StrokeCap = SKStrokeCap.Round
    };

    public static readonly BindableProperty ProgressProperty =
        BindableProperty.Create(nameof(Progress), typeof(double), typeof(SkiaProgressRing), 0.0,
            propertyChanged: (b, o, n) => ((SkiaProgressRing)b).Invalidate());

    public double Progress
    {
        get => (double)GetValue(ProgressProperty);
        set => SetValue(ProgressProperty, Math.Clamp(value, 0.0, 1.0));
    }

    public override void Draw(SKCanvas canvas, SKRect dirtyRect)
    {
        var center = new SKPoint(_bounds.MidX, _bounds.MidY);
        var radius = Math.Min(_bounds.Width, _bounds.Height) / 2 - _progressPaint.StrokeWidth;

        _trackPaint.Color = SKColors.LightGray;
        canvas.DrawCircle(center, radius, _trackPaint);

        _progressPaint.Color = SKColors.Blue;
        var sweepAngle = (float)(Progress * 360);

        using var path = new SKPath();
        path.AddArc(SKRect.Create(center.X - radius, center.Y - radius, radius * 2, radius * 2),
            -90, sweepAngle);

        canvas.DrawPath(path, _progressPaint);
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            _trackPaint?.Dispose();
            _progressPaint?.Dispose();
        }
        base.Dispose(disposing);
    }
}
```

